enumValidation.code:
function isValidEnumValue(value: unknown, validValues: string[]): boolean {
  return typeof value === 'string' && validValues.includes(value);
}

stringValidation.code:
function isValidString(value: unknown): boolean {
  return typeof value === 'string' && !value.includes('[object');
}

numberValidation.code:
function isValidNumber(value: unknown): boolean {
  return typeof value === 'number' &&
         !Number.isNaN(value) &&
         Number.isFinite(value);
}

dateValidation.code:
function isValidDate(value: unknown): boolean {
  if (value instanceof Date) {
    return !Number.isNaN(value.getTime());
  }
  if (typeof value === 'string') {
    const parsed = Date.parse(value);
    return !Number.isNaN(parsed);
  }
  return false;
}

safeCompare.code:
function safeCompare(a: unknown, b: unknown): number {
  if (!isValidNumber(a) && !isValidNumber(b)) return 0;
  if (!isValidNumber(a)) return 1;  // Invalid values sort last
  if (!isValidNumber(b)) return -1;
  return a - b;
}
